// TestRuleStatus_SemanticMeaning tests field semantics per spec (T007)
// Given: RuleStatus representing debounce statistics
// When: Examining typical usage scenario from spec
// Then: Field values make semantic sense
func TestRuleStatus_SemanticMeaning(t *testing.T) {
	// Scenario from spec: 27K-51K evaluations, near-zero triggers
	// After debouncing: ~80% reduction in evaluations
	rs := RuleStatus{
		DebounceDelayMs:    100,
		PendingEvaluations: 3,     // Currently waiting
		TotalEvaluations:   5400,  // 80% reduction from 27K
		TotalTriggers:      42,    // Actual threshold crossings
		DebouncedCount:     21600, // 27K - 5.4K = 21.6K deferred
	}

	// Semantic checks per data-model.md and spec requirements
	// DebouncedCount should represent evaluations that were deferred
	if rs.DebouncedCount < 0 {
		t.Errorf("DebouncedCount should be >= 0, got %d", rs.DebouncedCount)
	}

	// TotalEvaluations should be less than (TotalEvaluations + DebouncedCount) conceptually
	// i.e., we deferred more than we actually evaluated (80% reduction goal)
	if rs.TotalEvaluations > rs.DebouncedCount {
		t.Logf("Warning: TotalEvaluations (%d) > DebouncedCount (%d) - may not reflect 80%% reduction",
			rs.TotalEvaluations, rs.DebouncedCount)
	}

	// PendingEvaluations should be >= 0
	if rs.PendingEvaluations < 0 {
		t.Errorf("PendingEvaluations should be >= 0, got %d", rs.PendingEvaluations)
	}

	// TotalTriggers should not exceed TotalEvaluations
	if rs.TotalTriggers > rs.TotalEvaluations {
		t.Errorf("TotalTriggers (%d) should not exceed TotalEvaluations (%d)",
			rs.TotalTriggers, rs.TotalEvaluations)
	}
}

// TestRuleStatus_DebounceEffectiveness tests measuring debounce effectiveness (T007)
// Given: RuleStatus with evaluation statistics
// When: Calculating debounce effectiveness ratio
// Then: Can measure 80% reduction goal from spec
func TestRuleStatus_DebounceEffectiveness(t *testing.T) {
	tests := []struct {
		name              string
		rs                RuleStatus
		expectedReduction float64 // Expected reduction percentage
		tolerancePercent  float64
	}{
		{
			name: "80% reduction (spec goal)",
			rs: RuleStatus{
				TotalEvaluations: 5400,  // 20% of original
				DebouncedCount:   21600, // 80% deferred
			},
			expectedReduction: 0.80,
			tolerancePercent:  0.01,
		},
		{
			name: "no debouncing",
			rs: RuleStatus{
				TotalEvaluations: 27000,
				DebouncedCount:   0,
			},
			expectedReduction: 0.0,
			tolerancePercent:  0.01,
		},
		{
			name: "50% reduction",
			rs: RuleStatus{
				TotalEvaluations: 13500,
				DebouncedCount:   13500,
			},
			expectedReduction: 0.50,
			tolerancePercent:  0.01,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			total := float64(tt.rs.TotalEvaluations + tt.rs.DebouncedCount)
			if total == 0 {
				t.Skip("No evaluations to measure")
			}

			actualReduction := float64(tt.rs.DebouncedCount) / total

			diff := actualReduction - tt.expectedReduction
			if diff < 0 {
				diff = -diff
			}

			if diff > tt.tolerancePercent {
				t.Errorf("Expected %0.0f%% reduction, got %0.0f%%",
					tt.expectedReduction*100, actualReduction*100)
			}
		})
	}
}

